import * as React from "react";
import { cn } from "@/lib/utils";
import { focusRing, transitions } from "./lib/primitives";
import { Collapse } from "./lib/motion";

interface AccordionContextValue {
  openValues: string[];
  toggle: (item: string) => void;
}

const AccordionContext = React.createContext<AccordionContextValue | undefined>(
  undefined,
);

function useAccordionContext() {
  const ctx = React.useContext(AccordionContext);
  if (!ctx)
    throw new Error("Accordion components must be used within Accordion");
  return ctx;
}

const AccordionItemContext = React.createContext<string>("");

export interface AccordionProps extends React.HTMLAttributes<HTMLDivElement> {
  type?: "single" | "multiple";
  defaultValue?: string | string[];
  collapsible?: boolean;
}

export const Accordion = React.forwardRef<HTMLDivElement, AccordionProps>(
  (
    {
      type = "single",
      defaultValue,
      collapsible = true,
      children,
      className,
      ...props
    },
    ref,
  ) => {
    const initial = defaultValue
      ? Array.isArray(defaultValue)
        ? defaultValue
        : [defaultValue]
      : [];
    const [openValues, setOpenValues] = React.useState<string[]>(initial);

    const toggle = React.useCallback(
      (item: string) => {
        if (type === "single") {
          setOpenValues((prev) =>
            prev.includes(item) ? (collapsible ? [] : prev) : [item],
          );
        } else {
          setOpenValues((prev) =>
            prev.includes(item)
              ? prev.filter((v) => v !== item)
              : [...prev, item],
          );
        }
      },
      [type, collapsible],
    );

    return (
      <AccordionContext.Provider value={{ openValues, toggle }}>
        <div
          ref={ref}
          className={cn(
            "divide-y divide-border rounded-md border border-border",
            className,
          )}
          {...props}
        >
          {children}
        </div>
      </AccordionContext.Provider>
    );
  },
);
Accordion.displayName = "Accordion";

export interface AccordionItemProps extends React.HTMLAttributes<HTMLDivElement> {
  value: string;
}

export const AccordionItem = React.forwardRef<
  HTMLDivElement,
  AccordionItemProps
>(({ value, children, className, ...props }, ref) => (
  <AccordionItemContext.Provider value={value}>
    <div ref={ref} className={cn("px-4", className)} {...props}>
      {children}
    </div>
  </AccordionItemContext.Provider>
));
AccordionItem.displayName = "AccordionItem";

export interface AccordionTriggerProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {}

export const AccordionTrigger = React.forwardRef<
  HTMLButtonElement,
  AccordionTriggerProps
>(({ children, className, ...props }, ref) => {
  const { openValues, toggle } = useAccordionContext();
  const itemValue = React.useContext(AccordionItemContext);
  const isOpen = openValues.includes(itemValue);

  return (
    <button
      ref={ref}
      type="button"
      aria-expanded={isOpen}
      onClick={() => toggle(itemValue)}
      className={cn(
        "flex w-full items-center justify-between py-4 text-sm font-medium text-foreground",
        transitions.all,
        "hover:underline",
        focusRing,
        className,
      )}
      {...props}
    >
      {children}
      <svg
        xmlns="http://www.w3.org/2000/svg"
        width="16"
        height="16"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
        className={cn(
          "shrink-0 text-muted-foreground",
          transitions.transform,
          isOpen && "rotate-180",
        )}
        aria-hidden="true"
      >
        <path d="m6 9 6 6 6-6" />
      </svg>
    </button>
  );
});
AccordionTrigger.displayName = "AccordionTrigger";

export interface AccordionContentProps extends React.HTMLAttributes<HTMLDivElement> {}

export const AccordionContent = React.forwardRef<
  HTMLDivElement,
  AccordionContentProps
>(({ children, className, ...props }, ref) => {
  const { openValues } = useAccordionContext();
  const itemValue = React.useContext(AccordionItemContext);
  const isOpen = openValues.includes(itemValue);

  return (
    <Collapse open={isOpen}>
      <div
        ref={ref}
        className={cn("pb-4 pt-0 text-sm text-muted-foreground", className)}
        {...props}
      >
        {children}
      </div>
    </Collapse>
  );
});
AccordionContent.displayName = "AccordionContent";

/**
 * Design primitives
 *
 * Shared Tailwind class strings extracted from patterns that repeat across
 * every component. Import these instead of copy-pasting the same strings.
 *
 * Usage:
 *   import { focusRing, surface, transitions } from "@/lib/primitives"
 *   className={cn(surface, focusRing, className)}
 */

/** Full focus-visible ring used on every interactive element */
export const focusRing =
  "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background";

/** Inset focus ring (for buttons inside bordered containers) */
export const focusRingInset =
  "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset";

/** Bordered muted surface — code blocks, accordion, inline containers */
export const surface = "rounded-lg border border-border bg-muted";

/** Card surface — white/card background with shadow */
export const cardSurface = "rounded-lg border border-border bg-card shadow-sm";

/** Popover surface — used for tooltips, menus */
export const popoverSurface =
  "rounded-md border border-border bg-popover text-popover-foreground shadow-md";

/** Standard small muted body text */
export const mutedText = "text-sm text-muted-foreground";

/** Block-level vertical rhythm used by all prose components */
export const blockSpacing = "my-6";

/** Consistent transition timings */
export const transitions = {
  colors: "transition-colors duration-200",
  all: "transition-all duration-200",
  transform: "transition-transform duration-200",
  opacity: "transition-opacity duration-200",
} as const;

/** Chevron SVG (reused in accordion, reveal, spoiler) */
export const chevronPath = "m6 9 6 6 6-6";

import * as React from "react";

export interface CollapseProps {
  /** Whether the content is visible */
  open: boolean;
  children: React.ReactNode;
  className?: string;
}

/**
 * Collapse — animated height transition using CSS grid-template-rows.
 *
 * Technique: the outer div transitions between `grid-template-rows: 0fr`
 * (collapsed) and `1fr` (expanded). The inner div clips overflow.
 * This avoids JS height measurement and handles dynamic content naturally.
 *
 * @example
 * <Collapse open={isOpen}>
 *   <div className="py-4">content</div>
 * </Collapse>
 */
export function Collapse({ open, children, className }: CollapseProps) {
  return (
    <div
      aria-hidden={!open}
      style={{
        display: "grid",
        gridTemplateRows: open ? "1fr" : "0fr",
        transition: "grid-template-rows 220ms cubic-bezier(0.4, 0, 0.2, 1)",
      }}
      className={className}
    >
      <div style={{ overflow: "hidden" }}>{children}</div>
    </div>
  );
}
